class Solution {
public:
    int findMinimumOperations(string s1, string s2, string s3) {
        int m = s1.size(), n = s2.size(), p = s3.size();
        int i = m - 1, j = n - 1, k = p - 1;
        int count = 0;
        while (i > 0 && j > 0 && k > 0) {
            if (s1[i] == s2[j] && s2[j] == s3[k]) {
                i--;
                j--;
                k--;
            } else {
                count++;
                if (s1[i] != s2[j] && s1[i] != s3[k]) i--;
                if (s2[j] != s1[i] && s2[j] != s3[k]) j--;
                if (s3[k] != s1[i] && s3[k] != s2[j]) k--;
            }
        }
        if (i == 0 && j == 0 && k == 0) return count;
        else return -1;
    }
};
